 45→
 46→/* Icon button base (34x34) */
 47→.btn {
 48→  display: flex;
 49→  align-items: center;
 50→  justify-content: center;
 51→  width: 34px;
 52→  height: 34px;
 53→  padding: 0;
 54→  border-radius: var(--radius-sm);
 55→  font-size: 12px;
 56→  font-weight: 500;
 57→  letter-spacing: 0.01em;
 58→  color: var(--color-text-primary);
 59→  transition: background var(--duration-fast), transform var(--duration-fast);
 60→  white-space: nowrap;
 61→  position: relative;
 62→}
 63→
 64→.btn:hover {
 65→  background: rgba(0, 0, 0, 0.06);
 66→}
 67→
 68→.btn:active {
 69→  transform: scale(0.97);
 70→}
 71→
 72→.btn:disabled {
 73→  opacity: 0.45;
 74→  cursor: not-allowed;
 75→}
 76→
 77→.btn:disabled:hover {
 78→  background: transparent;
 79→}
 80→
 81→.btn:disabled:active {
 82→  transform: none;
 83→}
 84→
 85→.icon {
 86→  width: 18px;
 87→  height: 18px;
 88→  display: block;
 89→}
 90→
 91→/* Save with dirty pulsing dot via data attribute */
 92→.saveBtn {
 93→  composes: btn;
 94→}
 95→
 96→.saveBtn[data-dirty="true"]::after {
 97→  content: '';
 98→  position: absolute;
 99→  top: 5px;
100→  right: 5px;
101→  width: 6px;
102→  height: 6px;
103→  border-radius: 50%;
104→  background: var(--color-accent);
105→  animation: pulse 2s ease-in-out infinite;
106→}
107→
108→@keyframes pulse {
109→  0%, 100% { opacity: 1; }
110→  50% { opacity: 0.4; }
111→}
112→
113→/* Segmented pill control for view modes */
