132→  font-weight: 500;
133→  color: var(--color-text-secondary);
134→  background: transparent;
135→  transition: background var(--duration-fast), color var(--duration-fast), box-shadow var(--duration-fast);
136→  white-space: nowrap;
137→  cursor: pointer;
138→}
139→
140→.segmentedBtn:hover {
141→  color: var(--color-text-primary);
142→  background: rgba(0, 0, 0, 0.03);
143→}
144→
145→.segmentedBtnActive {
146→  composes: segmentedBtn;
147→  background: var(--color-segment-active-bg);
148→  color: var(--color-text-primary);
149→  font-weight: 600;
150→  box-shadow: var(--color-segment-active-shadow);
151→}
152→
153→/* Tool palette - inline row */
154→.toolPalette {
155→  display: flex;
156→  align-items: center;
157→  gap: 1px;
158→  padding: 0 var(--space-sm);
159→  flex-shrink: 0;
160→  border-left: 1px solid var(--color-border-subtle);
161→}
162→
163→.toolPaletteBtn {
164→  display: flex;
165→  align-items: center;
166→  justify-content: center;
167→  width: 32px;
168→  height: 32px;
