206→                onClick={() => handleDeleteFloor(entry)}
207→                title={`Delete ${entry.name}`}
208→                disabled={orderedFloors.length <= 1}
209→              >
210→                <TrashIcon />
211→              </button>
212→            </div>
213→          </div>
214→        ))}
215→      </Section>
